import{_ as o,o as t,c as r,a3 as n}from"./chunks/framework.CjquFG0V.js";const g=JSON.parse('{"title":"19. Consultation About Changes To Rosters Or Hours Or Work","description":"","frontmatter":{"title":"19. Consultation About Changes To Rosters Or Hours Or Work","eba":"Mental Health Services 2024-2028","topics":["hours","rosters","consultation"]},"headers":[],"relativePath":"ebas/mental-health/common-terms/consultation-disputes/19-consultation-about-changes-to-rosters-or-hours-or-work.md","filePath":"ebas/mental-health/common-terms/consultation-disputes/19-consultation-about-changes-to-rosters-or-hours-or-work.md"}'),s={name:"ebas/mental-health/common-terms/consultation-disputes/19-consultation-about-changes-to-rosters-or-hours-or-work.md"};function a(i,e,h,l,p,c){return t(),r("div",null,[...e[0]||(e[0]=[n('<h1 id="_19-consultation-about-changes-to-rosters-or-hours-or-work" tabindex="-1">19. Consultation About Changes To Rosters Or Hours Or Work <a class="header-anchor" href="#_19-consultation-about-changes-to-rosters-or-hours-or-work" aria-label="Permalink to &quot;19. Consultation About Changes To Rosters Or Hours Or Work&quot;">​</a></h1><p>This clause 19 applies where a change to regular rosters or ordinary hours of work (which may impact upon an employee, particularly in relation to their family and caring responsibilities) does not constitute &#39;Major Change&#39; in accordance with subclause 18.2(c).</p><p><strong>19.1</strong> Where an Employer proposes to change an Employee&#39;s regular roster or ordinary hours of work, the Employer must:</p><p><strong>(a)</strong> notify the relevant employee or employees of the proposed change; and</p><p><strong>(b)</strong> consult with the relevant employee or employees and their representative/s, if any, about the proposed change as described below.</p><p><strong>19.2</strong> As soon as practicable after proposing to introduce the change, the Employer must:</p><p><strong>(a)</strong> discuss with the relevant employee/s the introduction of the change, and</p><p><strong>(b)</strong> for the purposes of the discussion, provide to the relevant employee/s (and their representatives if any) all relevant information about the change including:</p><p><strong>(i)</strong> the nature of the change and when that change is proposed to commence; and</p><p><strong>(ii)</strong> information about what the Employer reasonable believes will be the effects of the change on the relevant Employees; and</p><p><strong>(iii)</strong> information about any other matters that the Employer reasonably believes are likely to affect the relevant employees; and</p><p><strong>(c)</strong> invite the relevant employees affected and their representatives, if any, to give their views about the impact of the proposed change (including any impact in relation to their family or caring responsibilities).</p><p><strong>19.3</strong> The Employer is not required to disclose confidential information to the relevant employees</p><p><strong>19.4</strong> The Employer must give prompt and genuine consideration to matters raised about the change by the relevant employees and consider health and safety impacts including fatigue.</p><p><strong>19.5</strong> In this term relevant employees means the Employee or Employees who may be affected by a change referred to in clause 19.1.</p><p><strong>19.6</strong> The requirement to consult under this clause 19 does not apply to an Employee where the change to an Employee&#39;s regular roster or ordinary hours of work is as a consequence of that Employee&#39;s irregular, sporadic or unpredictable working hours, self-rostering or, where permitted, a rotating roster.</p><p><strong>19.7</strong> The provisions of this clause 19 are to be read in conjunction with the terms of the engagement between the Employer and Employee, and other Agreement provisions concerning the scheduling of work and notice requirements.</p><p>Plain language terms: roster change, hours change consultation.</p>',18)])])}const m=o(s,[["render",a]]);export{g as __pageData,m as default};
